import android.content.Context
import android.content.SharedPreferences
import androidx.biometric.BiometricPrompt
import androidx.core.content.edit
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class BiometricAuthManager(private val context: Context) {
    private lateinit var biometricPrompt: BiometricPrompt
    private val sharedPreferences: SharedPreferences = context.getSharedPreferences("authenticated", Context.MODE_PRIVATE)

    suspend fun authenticate(): Boolean {
        if (sharedPreferences.contains("authenticated")) {
            return true
        }

        biometricPrompt = BiometricPrompt(context, Dispatchers.Main)
        val promptInfo = BiometricPrompt.PromptInfo.Builder()
                .setTitle("Login")
                .setSubtitle("Use fingerprint to login")
                .setNegativeButtonText("Use password")
                .build()

        biometricPrompt.authenticate(promptInfo) { result ->
            when (result.authenticationResult) {
                BiometricPrompt.AuthenticationResult.Success -> {
                    sharedPreferences.edit {
                        putBoolean("authenticated", true)
                    }
                }
                else -> {
                    // Fallback to password if biometric authentication fails
                    return false
                }
            }
        }

        return true
    }
}